    def update(self, iterable=(), **kwds):
        if hasattr(iterable, "keys"):
            for key in iterable.keys():
                self._update_feature(key, iterable[key])
        else:
            for key, value in iterable:
                self._update_feature(key, value)
        for key, value in kwds.items():
            self._update_feature(key, value)

    def _update_feature(self, key, value):
        # Deep-merge dictionaries (including nested Features) instead of overwriting them entirely.
        if key in self and isinstance(self[key], dict) and isinstance(value, dict):
            self[key].update(value)
            self._column_requires_decoding[key] = require_decoding(self[key])
        else:
            self[key] = value

